  clear() {
    this.memoryCache.clear();
  }
  // Get cache size (for debugging)
  size() {
    return this.memoryCache.size;
  }
  // Cleanup expired entries
  cleanup() {
    const now = Date.now();
    for (const [key, entry] of this.memoryCache.entries()) {
      if (now > entry.expiresAt) {
        this.memoryCache.delete(key);
      }
    }
  }
